    if review['user_id'] in user_ids:
        # Check date is from 2016 onwards
        date_str = review['date']
        try:
            if '2016' in date_str or '2017' in date_str or '2018' in date_str or '2019' in date_str or '2020' in date_str or '2021' in date_str:
                reviews_from_2016_users.append(review)
        except:
            continue

print(f"Filtered {len(reviews_from_2016_users)} reviews from 2016 users since 2016")

print('__RESULT__:')
print(json.dumps({
    'user_count': len(user_ids),
    'review_count': len(reviews_from_2016_users)
}))"}

